import { useEffect, useState } from "react";
import { backendURL } from "../Globals";

let JournalsComponent = () => {

    let [journals, setJournals] = useState ([])
    let [message, setMessage] = useState ("")

    useEffect( () => {
        getJournals();
    }, [])

    let getJournals = async () => {
       let response = await fetch(backendURL+"/journals")

       if (response.ok){
            let jsonData = await response.json()
            setJournals(jsonData)
       } else {
            setMessage("Error")
       }
    }

    return (
        <div>
            <h2>Journals</h2>
            { message != "" && <h3 className="errorMessage">{message}</h3>}
            <div className="item-list">
                {journals.map ( journal =>
                    (
                        <div className="item">
                            <h3>{journal.title}</h3>
                            <p className="price">{journal.issn}</p>
                            <p className="description">{journal.publisher}</p>
                        </div>
                    )

                )}
            </div>
        </div>
    )
}



export default JournalsComponent;
